import React, { useState } from 'react';

export default function ApologyWebsite() {
  const [forgiven, setForgiven] = useState(false);
  const [noClicks, setNoClicks] = useState(0);

  const handleNoClick = () => {
    setNoClicks(noClicks + 1);
  };

  return (
    <div className="min-h-screen bg-rose-50 flex flex-col items-center justify-center p-4 font-sans text-slate-800">
      <div className="max-w-md w-full bg-white rounded-2xl shadow-xl overflow-hidden p-8 text-center border border-rose-100">
        
        {!forgiven ? (
          <>
            {/* Placeholder for a cute graphic or a photo of the two of you */}
            <div className="w-32 h-32 mx-auto bg-rose-200 rounded-full mb-6 flex items-center justify-center overflow-hidden shadow-inner">
               <span className="text-4xl">🥺</span>
               {/* <img src="/us.jpg" alt="You and me" className="object-cover w-full h-full" /> */}
            </div>

            <h1 className="text-3xl font-bold mb-4 text-rose-600">I'm So Sorry</h1>
            
            <p className="text-lg mb-6 text-slate-600 leading-relaxed">
              I really messed up, and I hate knowing that I upset you. You mean everything to me, and I want to make things right. Can you find it in your heart to forgive me?
            </p>

            <div className="flex justify-center items-center gap-4 mt-8">
              <button 
                onClick={() => setForgiven(true)}
                className="px-6 py-3 bg-rose-500 hover:bg-rose-600 text-white font-semibold rounded-full transition-transform transform hover:scale-105 active:scale-95 shadow-md"
              >
                Yes, I forgive you ❤️
              </button>
              
              <button 
                onClick={handleNoClick}
                style={{ transform: `scale(${Math.max(0.5, 1 - noClicks * 0.1)})` }}
                className="px-6 py-3 bg-slate-200 hover:bg-slate-300 text-slate-700 font-semibold rounded-full transition-all"
              >
                {noClicks === 0 ? "No" : noClicks === 1 ? "Are you sure?" : "Please? 🥺"}
              </button>
            </div>
          </>
        ) : (
          <div className="animate-fade-in">
            <div className="w-32 h-32 mx-auto bg-green-100 rounded-full mb-6 flex items-center justify-center text-5xl shadow-inner">
              🎉
            </div>
            <h2 className="text-3xl font-bold mb-4 text-green-600">Thank You!</h2>
            <p className="text-lg text-slate-600">
              You're the best. I promise to make it up to you! Let me take you out to dinner tonight.
            </p>
          </div>
        )}
      </div>
    </div>
  );
}
